Javascript.initialise:
		var aDom = WPU.getCurrentCaseData(); 
		var partyDom = WPU.getSubjectPartyNode(aDom, true);   	
   		var partyId = XML.getNodeTextContent(partyDom.selectSingleNode("./PartyId"));
   		var upDom = aDom.selectSingleNode("//Parties/LitigiousParty[./PartyId = '"+partyId+"']");
   		var partyAgainst = XML.getNodeTextContent( upDom.selectSingleNode("Name"));
   		var dsd = WPU._getDsDOM();
   		var ifps = dsd.selectSingleNode("params/param/judgementxml/ds/MaintainJudgment/Judgments/Judgment[PartyId = '"+partyId+"']/InFavourParties");
   		
		for(var i = 0; i < ifps.childNodes.length; i++) 
		{
			var node = ifps.childNodes[i];
			Services.addNode(node, REF_DATA_XPATH + "/IFPTS");	
		}

Javascript.miscCode:
PartyFor.srcData = REF_DATA_XPATH + "/IFPTS";
PartyFor.rowXPath = "*";
PartyFor.keyXPath = "PartyKey";
PartyFor.columns = [
	{xpath: "PartyRoleCode"},
	{xpath: "Name"}
];
PartyFor.multipleSelection = true;

Context.initialise:

		var dsd = WPU._getDsDOM();
	   	var valNode = dsd.selectSingleNode("params/param/JudgementId");
		if (null!= valNode) { 
			var valVal = XML.getNodeTextContent(valNode);
	   		var ifps = dsd.selectSingleNode("params/param/judgementxml/ds/MaintainJudgment/Judgments/Judgment[JudgmentId = '"+valVal+"']/InFavourParties");
	   		var partyNodes = ifps.selectNodes("Party");
	   		if (null != partyNodes) {
	   			var partyNodesLen = partyNodes.length;
	   			for (var i=0; partyNodesLen > i; i++) {
	   				var partyNode = partyNodes[i];		   									
					Services.addNode(partyNode, REF_DATA_XPATH + "/IFPTS");	
	   			} 
	   		}					
		}
